div.p:
Formula: patch_value = S + A - P
Where: S = symbol_address, A = addend, P = site_virtual_address (Place)
| {
near: top-center
shape: text
}

inputs: "INPUT PARAMETERS (64-BIT)" {
style: {
fill: "#E8F4FD"
stroke: "#2196F3"
stroke-width: 2
shadow: true
}

P: |md
P (site_virtual_address)
Relocation site's virtual address
Type: uint64_t
| {
style.fill: "#BBDEFB"
}
}

calc: "STEP 1: CALCULATE RAW VALUE" {
style: {
fill: "#FFF3E0"
stroke: "#FF9800"
stroke-width: 2
}

logic: |md
c
int64_t computed;
computed = (int64_t)(S + A - P);

overflow: "STEP 2: OVERFLOW DETECTION" {
style: {
fill: "#FFEBEE"
stroke: "#F44336"
stroke-width: 2
}

ul.li:
PC: Program Counter (RIP on x86_64)
| {
near: bottom-right
style: {
fill: "#FAFAFA"
stroke: "#9E9E9E"
}
}
